// ---- INTERPOLATION HELPERS ----

function interpolateAnchors(anchors, year) {
  if (!anchors || anchors.length === 0) return null;
  // Clamp to data range
  const minYr = anchors[0].yr;
  const maxYr = anchors[anchors.length - 1].yr;
  if (year <= minYr) return anchors[0].v;
  if (year >= maxYr) return anchors[anchors.length - 1].v;
  // Find surrounding anchors
  for (let i = 0; i < anchors.length - 1; i++) {
    if (year >= anchors[i].yr && year <= anchors[i + 1].yr) {
      const t = (year - anchors[i].yr) / (anchors[i + 1].yr - anchors[i].yr);
      return anchors[i].v + t * (anchors[i + 1].v - anchors[i].v);
    }
  }
  return anchors[anchors.length - 1].v;
}

function getExporterValue(country, year) {
  const anchors = EXporter_ANCHORS[country];
  if (!anchors) return null;
  return interpolateAnchors(anchors, year);
}

function getImporterValue(country, year) {
  const anchors = IMPORTER_ANCHORS[country];
  if (!anchors) return null;
  return interpolateAnchors(anchors, year);
}

function getFlowValue(from, to, year) {
  const flow = FLOW_ANCHORS.find(f => f.from === from && f.to === to);
  if (!flow) return null;
  return interpolateAnchors(flow.anchors, year);
}

// Build full per-year exporter/importer data
function buildYearData(year) {
  const expData = {};
  const impData = {};
  const allCountries = new Set([
    ...Object.keys(EXporter_ANCHORS),
    ...Object.keys(IMPORTER_ANCHORS),
  ]);
  allCountries.forEach(c => {
    const ev = getExporterValue(c, year);
    const iv = getImporterValue(c, year);
    if (ev !== null) expData[c] = ev;
    if (iv !== null) impData[c] = iv;
  });
  return { expData, impData };
}

