function init() {
  initWarningBanner();
  var subtitle = document.querySelector('.app-subtitle');
  if (subtitle && !document.getElementById('yearDisplay')) {
    subtitle.innerHTML = '<span id="yearDisplay">' + currentYear + '</span> \u00b7 Multi-Year Explorer';
  }
  initYearSlider();
  initInsightsCarousel();
  initSparklineChart();
  initMap();
  initViewToggle();
  initUnitToggle();
  initAusFocus();
  initFlowTable();
  initPanelClose();
  updateForYear(currentYear);
}

// ---- WARNING BANNER ----
function initWarningBanner() {
  const banner = document.getElementById('warningBanner');
  const closeBtn = document.getElementById('bannerClose');
  if (!banner || !closeBtn) return;
  if (sessionStorage.getItem('winebannerDismissed')) {
    banner.style.display = 'none';
    return;
  }
  closeBtn.addEventListener('click', function() {
    banner.style.display = 'none';
    sessionStorage.setItem('winebannerDismissed', '1');
  });
}

// ---- YEAR SLIDER ----
function initYearSlider() {
  const slider = document.getElementById('yearSlider');
  const yearDisplay = document.getElementById('yearDisplay');
  const eventTag = document.getElementById('eventTag');
  if (!slider) return;

  slider.min = 2000;
  slider.max = 2025;
  slider.value = currentYear;

  if (yearDisplay) yearDisplay.textContent = currentYear;
  if (eventTag) {
    if (EVENTS[currentYear]) {
      eventTag.textContent = EVENTS[currentYear];
      eventTag.style.display = '';
    } else {
      eventTag.style.display = 'none';
    }
  }

  slider.addEventListener('input', function() {
    const yr = parseInt(this.value, 10);
    setYear(yr);
  });
}

function setYear(yr) {
  currentYear = yr;
  const yearDisplay = document.getElementById('yearDisplay');
  if (yearDisplay) yearDisplay.textContent = yr;

  const eventTag = document.getElementById('eventTag');
  if (eventTag) {
    if (EVENTS[yr]) {
      eventTag.textContent = EVENTS[yr];
      eventTag.style.display = '';
    } else {
      eventTag.style.display = 'none';
    }
  }

  updateForYear(yr);
}

// ---- GLOBAL SPARKLINE CHART ----
function initSparklineChart() {
  const svg = document.getElementById('sparklineSvg');
  if (!svg) return;

  const W = 320, H = 52, PAD = 6;
  const years = Object.keys(YEARLY_GLOBAL).map(Number).sort();
  const vols = years.map(y => YEARLY_GLOBAL[y].vol);
  const vals = years.map(y => YEARLY_GLOBAL[y].val);

  const maxVol = Math.max(...vols);
  const minVol = Math.min(...vols);
  const maxVal = Math.max(...vals);
  const minVal = Math.min(...vals);

  const xStep = (W - PAD * 2) / (years.length - 1);

  function buildArea(data, minV, maxV, color) {
    const pts = data.map((v, i) => {
      const x = PAD + i * xStep;
      const y = PAD + (1 - (v - minV) / (maxV - minV || 1)) * (H - PAD * 2);
      return [x, y];
    });
    const linePath = pts.map((p, i) => (i === 0 ? 'M' : 'L') + p[0] + ',' + p[1]).join(' ');
    const fillPath = linePath + ' L' + pts[pts.length - 1][0] + ',' + (H - PAD) + ' L' + pts[0][0] + ',' + (H - PAD) + ' Z';
    return { linePath, fillPath, pts };
  }

  const valData = buildArea(vals, minVal, maxVal, '#f4c878');
  const volData = buildArea(vols, minVol, maxVol, '#8b3a62');

  // Volume area (behind)
  const volFill = document.createElementNS('http://www.w3.org/2000/svg', 'path');
  volFill.setAttribute('d', volData.fillPath);
  volFill.setAttribute('fill', 'rgba(139,58,98,0.25)');
  volFill.setAttribute('class', 'spark-fill');
  svg.appendChild(volFill);

  const volLine = document.createElementNS('http://www.w3.org/2000/svg', 'path');
  volLine.setAttribute('d', volData.linePath);
  volLine.setAttribute('fill', 'none');
  volLine.setAttribute('stroke', 'rgba(139,58,98,0.6)');
  volLine.setAttribute('stroke-width', '1.5');
  volLine.setAttribute('class', 'spark-line');
  volLine.setAttribute('id', 'sparkVolLine');
  svg.appendChild(volLine);

  // Value area (front)
  const valFill = document.createElementNS('http://www.w3.org/2000/svg', 'path');
  valFill.setAttribute('d', valData.fillPath);
  valFill.setAttribute('fill', 'rgba(244,200,120,0.15)');
  valFill.setAttribute('class', 'spark-fill');
  svg.appendChild(valFill);

  const valLine = document.createElementNS('http://www.w3.org/2000/svg', 'path');
  valLine.setAttribute('d', valData.linePath);
  valLine.setAttribute('fill', 'none');
  valLine.setAttribute('stroke', '#f4c878');
  valLine.setAttribute('stroke-width', '2');
  valLine.setAttribute('class', 'spark-line');
  valLine.setAttribute('id', 'sparkValLine');
  svg.appendChild(valLine);

  // Current year indicator dot
  const yearsSorted = years;
  const currIdx = yearsSorted.indexOf(currentYear);
  if (currIdx >= 0) {
    const cx = PAD + currIdx * xStep;
    const cyVol = PAD + (1 - (vols[currIdx] - minVol) / (maxVol - minVol || 1)) * (H - PAD * 2);
    const cyVal = PAD + (1 - (vals[currIdx] - minVal) / (maxVal - minVal || 1)) * (H - PAD * 2);

    // Vertical line
    const vLine = document.createElementNS('http://www.w3.org/2000/svg', 'line');
    vLine.setAttribute('x1', cx);
    vLine.setAttribute('y1', PAD);
    vLine.setAttribute('x2', cx);
    vLine.setAttribute('y2', H - PAD);
    vLine.setAttribute('stroke', 'rgba(244,200,120,0.4)');
    vLine.setAttribute('stroke-width', '1');
    vLine.setAttribute('stroke-dasharray', '3,2');
    vLine.setAttribute('class', 'spark-vline');
    vLine.setAttribute('id', 'sparkVLine');
    svg.appendChild(vLine);

    // Value dot
    const valDot = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
    valDot.setAttribute('cx', cx);
    valDot.setAttribute('cy', cyVal);
    valDot.setAttribute('r', '3');
    valDot.setAttribute('fill', '#f4c878');
    valDot.setAttribute('class', 'spark-dot');
    valDot.setAttribute('id', 'sparkValDot');
    svg.appendChild(valDot);

    // Volume dot
    const volDot = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
    volDot.setAttribute('cx', cx);
    volDot.setAttribute('cy', cyVol);
    volDot.setAttribute('r', '2.5');
    volDot.setAttribute('fill', 'rgba(139,58,98,0.8)');
    volDot.setAttribute('class', 'spark-dot');
    volDot.setAttribute('id', 'sparkVolDot');
    svg.appendChild(volDot);
  }
}

function updateSparklineForYear(yr) {
  const svg = document.getElementById('sparklineSvg');
  if (!svg) return;

  const years = Object.keys(YEARLY_GLOBAL).map(Number).sort();
  const vols = years.map(y => YEARLY_GLOBAL[y].vol);
  const vals = years.map(y => YEARLY_GLOBAL[y].val);
  const minVol = Math.min(...vols), maxVol = Math.max(...vols);
  const minVal = Math.min(...vals), maxVal = Math.max(...vals);

  const W = 320, H = 52, PAD = 6;
  const xStep = (W - PAD * 2) / (years.length - 1);
  const currIdx = years.indexOf(yr);
  if (currIdx < 0) return;

  const cx = PAD + currIdx * xStep;
  const cyVol = PAD + (1 - (vols[currIdx] - minVol) / (maxVol - minVol || 1)) * (H - PAD * 2);
  const cyVal = PAD + (1 - (vals[currIdx] - minVal) / (maxVal - minVal || 1)) * (H - PAD * 2);

  ['sparkVLine', 'sparkValDot', 'sparkVolDot'].forEach(function(id) {
    const el = document.getElementById(id);
    if (el) {
      if (id === 'sparkVLine') {
        el.setAttribute('x1', cx);
        el.setAttribute('x2', cx);
      } else {
        el.setAttribute('cx', cx);
        if (id === 'sparkValDot') el.setAttribute('cy', cyVal);
        else if (id === 'sparkVolDot') el.setAttribute('cy', cyVol);
      }
    }
  });
}

// ---- INSIGHTS CAROUSEL ----
function initInsightsCarousel() {
  const track = document.getElementById('insightsTrack');
  const dotsContainer = document.getElementById('insightsDots');
  if (!track || !dotsContainer) return;

  const insights = [
    { icon: '🍷', text: '<span class="insight-headline">France dominates global exports</span><span class="insight-detail">More than the next 3 countries combined — {{val}}bn EUR in {{year}}</span>' },
    { icon: '🇦🇺', text: '<span class="insight-headline">Australia wine exports surge</span><span class="insight-detail">{{val}}bn EUR in {{year}} — recovery driven by China market return</span>' },
    { icon: '🇺🇸', text: '<span class="insight-headline">USA — world\'s biggest importer</span><span class="insight-detail">{{val}}bn EUR in {{year}} — 18% of global wine imports</span>' },
    { icon: '🌏', text: '<span class="insight-headline">China wine market rebounds</span><span class="insight-detail">Imports jumped +37% YoY in 2024 after tariff removal</span>' },
    { icon: '📈', text: '<span class="insight-headline">Global wine trade value</span><span class="insight-detail">US${{val}}B in {{year}} — {{yoy}} from previous year</span>' },
    { icon: '🌐', text: '<span class="insight-headline">Global wine trade volume</span><span class="insight-detail">{{vol}}M hL in {{year}} — {{yoy_vol}} from previous year</span>' },
    { icon: '🇮🇹', text: '<span class="insight-headline">Italy — #2 exporter</span><span class="insight-detail">{{val}}bn EUR in {{year}} — strong bulk wine performance</span>' },
    { icon: '🇪🇸', text: '<span class="insight-headline">Spain — #3 exporter by volume</span><span class="insight-detail">High volume, lower price — bulk wine powerhouse</span>' },
  ];

  insights.forEach(function(ins, i) {
    const card = document.createElement('div');
    card.className = 'insight-card';
    card.innerHTML = '<span class="insight-icon">' + ins.icon + '</span>' + ins.text;
    card.setAttribute('aria-label', 'Insight ' + (i + 1));
    track.appendChild(card);

    const dot = document.createElement('button');
    dot.className = 'insight-dot' + (i === 0 ? ' active' : '');
    dot.setAttribute('aria-label', 'Go to insight ' + (i + 1));
    dot.addEventListener('click', function() { goToInsight(i); });
    dotsContainer.appendChild(dot);
  });

  function scheduleNext() {
    insightTimer = setTimeout(function() {
      insightIndex = (insightIndex + 1) % insights.length;
      goToInsight(insightIndex);
      scheduleNext();
    }, 5000);
  }
  scheduleNext();
}

function goToInsight(idx) {
  insightIndex = idx;
  const track = document.getElementById('insightsTrack');
  if (track) track.style.transform = 'translateX(-' + (idx * 100) + '%)';
  document.querySelectorAll('.insight-dot').forEach(function(d, i) {
    d.classList.toggle('active', i === idx);
  });
}

function buildInsightText(tmpl, yr) {
  var gv = YEARLY_GLOBAL[yr] || YEARLY_GLOBAL[2024];
  var prevYr = yr > 2000 ? yr - 1 : yr;
  var gvPrev = YEARLY_GLOBAL[prevYr] || gv;
  var yoyVal = gvPrev.val ? (((gv.val - gvPrev.val) / gvPrev.val) * 100).toFixed(1) : '0.0';
  var yoyVol = gvPrev.vol ? (((gv.vol - gvPrev.vol) / gvPrev.vol) * 100).toFixed(1) : '0.0';
  var expFr = getExporterValue('France', yr);
  var expAu = getExporterValue('Australia', yr);
  var impUs = getImporterValue('USA', yr);

  return tmpl
    .replace(/\{\{year\}\}/g, yr)
    .replace(/\{\{val\}\}/g, (expFr || 0).toFixed(1))
    .replace(/\{\{vol\}\}/g, gv.vol)
    .replace(/\{\{yoy\}\}/g, (parseFloat(yoyVal) >= 0 ? '+' : '') + yoyVal + '%')
    .replace(/\{\{yoy_vol\}\}/g, (parseFloat(yoyVol) >= 0 ? '+' : '') + yoyVol + '%');
}

// ---- MAP ----
function initMap() {
  const mapGroup = document.getElementById('mapGroup');
  if (!mapGroup) return;

  Object.keys(ALL_COUNTRY_PATHS).forEach(function(name) {
    const pathEl = document.createElementNS('http://www.w3.org/2000/svg', 'path');
    pathEl.setAttribute('d', ALL_COUNTRY_PATHS[name].d);
    pathEl.setAttribute('id', 'country-' + name.replace(/\s+/g, '-'));
    var isWine = ALL_COUNTRY_PATHS[name].wine;
    pathEl.setAttribute('class', isWine ? 'country-path' : 'country-path non-wine');
    if (isWine) {
      pathEl.setAttribute('tabindex', '0');
      pathEl.setAttribute('role', 'button');
      pathEl.setAttribute('aria-label', name);
      pathEl.dataset.country = name;

      pathEl.addEventListener('click', function() { selectCountry(name); });
      pathEl.addEventListener('keydown', function(e) {
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault();
          selectCountry(name);
        }
      });
    }

    mapGroup.appendChild(pathEl);
  });

  renderMapColors();
  renderArcs();
}

function renderMapColors() {
  const container = document.querySelector('.map-container');
  if (!container) return;
  container.dataset.view = currentView;

  const { expData, impData } = buildYearData(currentYear);

  Object.keys(ALL_COUNTRY_PATHS).forEach(function(name) {
    const pathEl = document.getElementById('country-' + name.replace(/\s+/g, '-'));
    if (!pathEl) return;

    // Reset classes using setAttribute for SVG
    var isWine = ALL_COUNTRY_PATHS[name].wine;
    pathEl.setAttribute('class', isWine ? 'country-path' : 'country-path non-wine');
    if (!isWine) return;

    if (currentView === 'export') {
      const ev = expData[toDataName(name)];
      if (ev !== undefined) {
        const level = getExportLevel(ev);
        pathEl.setAttribute('class', 'country-path level-' + level + ' has-exports');
      }
    } else if (currentView === 'import') {
      const iv = impData[toDataName(name)];
      if (iv !== undefined) {
        const level = getImportLevel(iv);
        pathEl.setAttribute('class', 'country-path level-' + level + ' has-imports');
      }
    } else if (currentView === 'surplus') {
      const ev = expData[name] || 0;
      const iv = impData[name] || 0;
      const bal = ev - iv;
      if (bal > 0.3) pathEl.setAttribute('class', 'country-path surplus');
      else if (bal < -0.3) pathEl.setAttribute('class', 'country-path deficit');
      else pathEl.setAttribute('class', 'country-path neutral');
    }

    if (ausMode && name === 'Australia') {
      pathEl.setAttribute('class', pathEl.getAttribute('class') + ' aus-highlight');
    }
    if (selectedCountry === name) {
      pathEl.setAttribute('class', pathEl.getAttribute('class') + ' selected');
    }
  });
}

function getExportLevel(val) {
  if (val >= 10) return 5;
  if (val >= 5) return 4;
  if (val >= 2) return 3;
  if (val >= 0.5) return 2;
  return 1;
}

function getImportLevel(val) {
  if (val >= 5) return 5;
  if (val >= 2) return 4;
  if (val >= 1) return 3;
  if (val >= 0.5) return 2;
  return 1;
}

function renderArcs() {
  const arcsGroup = document.getElementById('arcsGroup');
  if (!arcsGroup) return;
  arcsGroup.innerHTML = '';

  // Determine max flow for this year to scale arc thickness
  const flowsThisYear = FLOW_ANCHORS.map(function(f) {
    const v = getFlowValue(f.from, f.to, currentYear);
    return { from: f.from, to: f.to, value: v };
  }).filter(function(f) { return f.value !== null && f.value > 0; });

  const maxFlow = Math.max(...flowsThisYear.map(function(f) { return f.value; }), 0.01);

  const gradId = currentView === 'export' ? 'arcGradExport' :
                 currentView === 'import' ? 'arcGradImport' : 'arcGradSurplus';

  flowsThisYear.forEach(function(flow, i) {
    const from = COUNTRY_CENTERS[toDataName(flow.from)] || COUNTRY_CENTERS[flow.from];
    const to = COUNTRY_CENTERS[toDataName(flow.to)] || COUNTRY_CENTERS[flow.to];
    if (!from || !to) return;

    const midX = (from[0] + to[0]) / 2;
    const midY = (from[1] + to[1]) / 2;
    const dist = Math.sqrt((to[0] - from[0]) * (to[0] - from[0]) + (to[1] - from[1]) * (to[1] - from[1]));
    const arcH = dist * 0.22 + 25;
    const ctrlX = midX;
    const ctrlY = Math.min(from[1], to[1]) - arcH - 20;

    const pathD = 'M' + from[0] + ',' + from[1] + ' Q' + ctrlX + ',' + ctrlY + ' ' + to[0] + ',' + to[1];
    const thickness = 0.8 + (flow.value / maxFlow) * 3.5;

    const pathEl = document.createElementNS('http://www.w3.org/2000/svg', 'path');
    pathEl.setAttribute('d', pathD);
    pathEl.setAttribute('class', 'trade-arc');
    pathEl.setAttribute('stroke', 'url(#' + gradId + ')');
    pathEl.setAttribute('stroke-width', thickness.toFixed(2));
    pathEl.dataset.from = flow.from;
    pathEl.dataset.to = flow.to;
    pathEl.dataset.value = flow.value.toFixed(3);

    pathEl.addEventListener('click', function(e) {
      e.stopPropagation();
      highlightArc(pathEl, flow);
    });

    arcsGroup.appendChild(pathEl);
  });

  animateArcs();
}

function animateArcs() {
  if (reducedMotion) return;
  const arcs = document.querySelectorAll('.trade-arc');
  arcs.forEach(function(arc, i) {
    arc.style.opacity = '0';
    arc.style.transition = 'opacity 0.4s ease ' + (i * 15) + 'ms';
    setTimeout(function() { arc.style.opacity = '0.65'; }, 50 + i * 15);
  });
}

function highlightArc(arcEl, flow) {
  document.querySelectorAll('.trade-arc').forEach(function(a) {
    if (a === arcEl) {
      a.setAttribute('class', 'trade-arc highlighted');
      a.style.opacity = '1';
      a.style.strokeWidth = (parseFloat(a.getAttribute('stroke-width')) + 1).toFixed(2);
    } else {
      a.setAttribute('class', 'trade-arc');
      a.style.opacity = '0.12';
    }
  });
  highlightedArc = arcEl;
  selectCountry(flow.from);
}

function clearArcHighlight() {
  document.querySelectorAll('.trade-arc').forEach(function(a) {
    a.setAttribute('class', 'trade-arc');
    a.style.opacity = '0.65';
  });
  highlightedArc = null;
}

// ---- TOGGLES ----
function initViewToggle() {
  document.querySelectorAll('.toggle-btn').forEach(function(btn) {
    btn.addEventListener('click', function() {
      currentView = btn.dataset.view;
      document.querySelectorAll('.toggle-btn').forEach(function(b) { b.classList.remove('active'); });
      btn.classList.add('active');
      clearArcHighlight();
      renderMapColors();
      renderArcs();
      updateLegendGradient();
    });
  });
}

function initUnitToggle() {
  document.querySelectorAll('.unit-toggle-btn').forEach(function(btn) {
    btn.addEventListener('click', function() {
      document.querySelectorAll('.unit-toggle-btn').forEach(function(b) { b.classList.remove('active'); });
      btn.classList.add('active');
      currentUnit = btn.dataset.unit;
      renderMapColors();
      if (selectedCountry) showCountryPanel(selectedCountry);
      refreshFlowTable();
    });
  });
}

function updateLegendGradient() {
  const grad = document.getElementById('legendGradient');
  if (!grad) return;
  if (currentView === 'export') {
    grad.style.background = 'linear-gradient(to right, #3A1028, #C8963E, #F4C878)';
  } else if (currentView === 'import') {
    grad.style.background = 'linear-gradient(to right, #3A1028, #7A2250, #9A2A60)';
  } else {
    grad.style.background = 'linear-gradient(to right, #7A2250, #2A6A2A, #6BC76B)';
  }
}

function initAusFocus() {
  const btn = document.getElementById('ausFocusBtn');
  if (!btn) return;
  btn.addEventListener('click', function() {
    ausMode = !ausMode;
    btn.classList.toggle('active', ausMode);
    if (ausMode) {
      selectCountry('Australia');
      document.querySelectorAll('.trade-arc').forEach(function(arc) {
        var from = arc.dataset.from;
        var to = arc.dataset.to;
        if (from === 'Australia' || to === 'Australia') {
          arc.style.opacity = '0.9';
        } else {
          arc.style.opacity = '0.08';
        }
      });
    } else {
      document.querySelectorAll('.trade-arc').forEach(function(arc) {
        arc.style.opacity = '0.65';
      });
    }
    renderMapColors();
  });
}

// ---- COUNTRY PANEL ----
function selectCountry(name) {
  var dataName = toDataName(name);
  selectedCountry = name;
  renderMapColors();
  showCountryPanel(name);
}

function showCountryPanel(name) {
  const panel = document.getElementById('countryPanel');
  if (!panel) return;

  var expVal = getExporterValue(name, currentYear);
  var impVal = getImporterValue(name, currentYear);

  // Build a mini sparkline SVG for this country
  var miniSparkline = buildCountrySparkline(name);

  var flag = getCountryFlag(name);
  var flagEl = document.getElementById('panelFlag');
  var nameEl = document.getElementById('panelCountryName');
  var subtitleEl = document.getElementById('panelSubtitle');
  var statsEl = document.getElementById('panelStats');
  var flowsEl = document.getElementById('panelFlows');
  var barChart = document.getElementById('panelBarChart');

  if (flagEl) flagEl.textContent = flag;
  if (nameEl) nameEl.textContent = name;

  var subtitleParts = [];
  if (expVal !== null) subtitleParts.push('Exports \u20AC' + expVal.toFixed(2) + 'B');
  if (impVal !== null) subtitleParts.push('Imports \u20AC' + impVal.toFixed(2) + 'B');
  if (subtitleEl) subtitleEl.textContent = subtitleParts.join(' \u00B7 ') || 'No major wine trade data';

  var balance = (expVal || 0) - (impVal || 0);
  var balClass = balance >= 0 ? 'surplus' : 'deficit';
  var balDir = balance >= 0 ? 'Net exporter' : 'Net importer';

  if (statsEl) {
    statsEl.innerHTML = '';
    statsEl.innerHTML =
      '<div class="stat-card export-stat">' +
        '<div class="stat-label">Exports</div>' +
        '<div class="stat-value">' + (expVal !== null ? '\u20AC' + expVal.toFixed(2) + 'B' : '\u2014') + '</div>' +
      '</div>' +
      '<div class="stat-card import-stat">' +
        '<div class="stat-label">Imports</div>' +
        '<div class="stat-value">' + (impVal !== null ? '\u20AC' + impVal.toFixed(2) + 'B' : '\u2014') + '</div>' +
      '</div>' +
      '<div class="stat-card balance-stat ' + balClass + '">' +
        '<div class="stat-label">Balance</div>' +
        '<div class="stat-value">' + (balance >= 0 ? '+' : '') + '\u20AC' + balance.toFixed(2) + 'B</div>' +
        '<div class="stat-change ' + (balance >= 0 ? 'up' : 'down') + '">' + balDir + '</div>' +
      '</div>';
  }

  // Country sparkline
  if (barChart) {
    barChart.innerHTML = '<h4>Export trend (2000\u20142024)</h4>' + miniSparkline;
  }

  // Top flows for this country
  if (flowsEl) {
    var outFlows = FLOW_ANCHORS.filter(function(f) { return f.from === dataName || f.from === name; })
      .map(function(f) { return { from: f.from, to: f.to, value: getFlowValue(f.from, f.to, currentYear) }; })
      .filter(function(f) { return f.value !== null && f.value > 0; })
      .sort(function(a, b) { return b.value - a.value; })
      .slice(0, 5);

    var inFlows = FLOW_ANCHORS.filter(function(f) { return f.to === dataName || f.to === name; })
      .map(function(f) { return { from: f.from, to: f.to, value: getFlowValue(f.from, f.to, currentYear) }; })
      .filter(function(f) { return f.value !== null && f.value > 0; })
      .sort(function(a, b) { return b.value - a.value; })
      .slice(0, 5);

    flowsEl.innerHTML =
      '<div class="flows-col">' +
        '<h4>Exports to</h4>' +
        (outFlows.length ? outFlows.map(function(f) {
          return '<div class="flow-item" data-from="' + f.from + '" data-to="' + f.to + '">' +
            '<span class="flow-partner">' + f.to + '</span>' +
            '<span class="flow-value">\u20AC' + f.value.toFixed(2) + 'B</span></div>';
        }).join('') : '<div class="flow-item"><span class="flow-partner">No data</span></div>') +
      '</div>' +
      '<div class="flows-col">' +
        '<h4>Imports from</h4>' +
        (inFlows.length ? inFlows.map(function(f) {
          return '<div class="flow-item" data-from="' + f.from + '" data-to="' + f.to + '">' +
            '<span class="flow-partner">' + f.from + '</span>' +
            '<span class="flow-value">\u20AC' + f.value.toFixed(2) + 'B</span></div>';
        }).join('') : '<div class="flow-item"><span class="flow-partner">No data</span></div>') +
      '</div>';

    flowsEl.querySelectorAll('.flow-item').forEach(function(item) {
      item.addEventListener('click', function() {
        var from = item.dataset.from;
        var to = item.dataset.to;
        var arc = document.querySelector('.trade-arc[data-from="' + from + '"][data-to="' + to + '"]');
        if (arc) highlightArc(arc, { from: from, to: to, value: parseFloat(arc.dataset.value) });
      });
    });
  }

  // Share bar
  var sharePct = document.getElementById('panelSharePct');
  var shareFill = document.getElementById('panelShareFill');
  if (sharePct && shareFill) {
    var globalVal = YEARLY_GLOBAL[currentYear] ? YEARLY_GLOBAL[currentYear].val : 36;
    var countryVal = Math.max(expVal || 0, impVal || 0);
    var pct = ((countryVal / globalVal) * 100).toFixed(1);
    sharePct.textContent = pct + '%';
    shareFill.style.width = pct + '%';
  }

  panel.setAttribute('aria-hidden', 'false');
  ensureBackdrop();
}

function buildCountrySparkline(name) {
  var svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
  svg.setAttribute('class', 'country-sparkline');
  svg.setAttribute('viewBox', '0 0 200 40');
  svg.setAttribute('preserveAspectRatio', 'none');

  var years = Object.keys(YEARLY_GLOBAL).map(Number).sort();
  var expVals = years.map(function(y) { return getExporterValue(name, y); });
  var impVals = years.map(function(y) { return getImporterValue(name, y); });

  var hasExp = expVals.some(function(v) { return v !== null; });
  var hasImp = impVals.some(function(v) { return v !== null; });

  if (!hasExp && !hasImp) {
    var txt = document.createElementNS('http://www.w3.org/2000/svg', 'text');
    txt.setAttribute('x', '100');
    txt.setAttribute('y', '24');
    txt.setAttribute('text-anchor', 'middle');
    txt.setAttribute('fill', '#8A8278');
    txt.setAttribute('font-size', '10');
    txt.textContent = 'No export data';
    svg.appendChild(txt);
    return svg.outerHTML;
  }

  var allVals = [].concat(expVals.filter(function(v) { return v !== null; }), impVals.filter(function(v) { return v !== null; }));
  var minV = Math.min(...allVals);
  var maxV = Math.max(...allVals);
  var range = maxV - minV || 0.1;

  var W = 200, H = 40, PAD = 4;
  var xStep = (W - PAD * 2) / (years.length - 1);

  function makeLine(data, color, dashed) {
    var pts = data.map(function(v, i) {
      if (v === null) return null;
      var x = PAD + i * xStep;
      var y = PAD + (1 - (v - minV) / range) * (H - PAD * 2);
      return [x, y];
    }).filter(function(p) { return p !== null; });

    if (pts.length < 2) return '';

    var linePath = pts.map(function(p, i) { return (i === 0 ? 'M' : 'L') + p[0].toFixed(1) + ',' + p[1].toFixed(1); }).join(' ');

    var pathEl = document.createElementNS('http://www.w3.org/2000/svg', 'path');
    pathEl.setAttribute('d', linePath);
    pathEl.setAttribute('fill', 'none');
    pathEl.setAttribute('stroke', color);
    pathEl.setAttribute('stroke-width', '1.5');
    if (dashed) pathEl.setAttribute('stroke-dasharray', '3,2');
    return pathEl;
  }

  if (hasImp) svg.appendChild(makeLine(impVals, '#8b3a62', false));
  if (hasExp) svg.appendChild(makeLine(expVals, '#f4c878', true));

  // Current year indicator
  var currIdx = years.indexOf(currentYear);
  if (currIdx >= 0) {
    var cx = PAD + currIdx * xStep;
    var vLine = document.createElementNS('http://www.w3.org/2000/svg', 'line');
    vLine.setAttribute('x1', cx);
    vLine.setAttribute('y1', PAD);
    vLine.setAttribute('x2', cx);
    vLine.setAttribute('y2', H - PAD);
    vLine.setAttribute('stroke', 'rgba(244,200,120,0.5)');
    vLine.setAttribute('stroke-width', '1');
    vLine.setAttribute('stroke-dasharray', '2,2');
    svg.appendChild(vLine);
  }

  return svg.outerHTML;
}

function getCountryFlag(name) {
  var flags = {
    France: '\uD83C\uDDEB\uD83C\uDDF7', Italy: '\uD83C\uDDEE\uD83C\uDDF9', Spain: '\uD83C\uDDEA\uD83C\uDDF8',
    Australia: '\uD83C\uDDE6\uD83C\uDDFA', Chile: '\uD83C\uDDE8\uD83C\uDDF1', USA: '\uD83C\uDDFA\uD83C\uDDF8',
    'New Zealand': '\uD83C\uDDF3\uD83C\uDDFF', Germany: '\uD83C\uDDE9\uD83C\uDDEA', Portugal: '\uD83C\uDDF5\uD83C\uDDF9',
    Argentina: '\uD83C\uDDE6\uD83C\uDDF7', 'South Africa': '\uD83C\uDDFF\uD83C\uDDE6', Belgium: '\uD83C\uDDE7\uD83C\uDDEA',
    Singapore: '\uD83C\uDDF8\uD83C\uDDEC', Netherlands: '\uD83C\uDDF3\uD83C\uDDF1', UK: '\uD83C\uDDEC\uD83C\uDDE7',
    Georgia: '\uD83C\uDDEC\uD83C\uDDEA', Austria: '\uD83C\uDDE6\uD83C\uDDF9', 'Hong Kong': '\uD83C\uDDED\uD83C\uDDF0',
    Denmark: '\uD83C\uDDE9\uD83C\uDDF0', Hungary: '\uD83C\uDDED\uD83C\uDDFA', Canada: '\uD83C\uDDE8\uD83C\uDDE6',
    Japan: '\uD83C\uDDEF\uD83C\uDDF5', 'mainland China': '\uD83C\uDDE8\uD83C\uDDF3',
    Switzerland: '\uD83C\uDDE8\uD83C\uDDED', Sweden: '\uD83C\uDDF8\uD83C\uDDEA', Russia: '\uD83C\uDDF7\uD83C\uDDFA',
    Brazil: '\uD83C\uDDE7\uD83C\uDDF7', Norway: '\uD83C\uDDF3\uD83C\uDDF4', 'South Korea': '\uD83C\uDDF0\uD83C\uDDF7',
    Ireland: '\uD83C\uDDEE\uD83C\uDDEA', Poland: '\uD83C\uDDF5\uD83C\uDDF1', Mexico: '\uD83C\uDDF2\uD83C\uDDFD',
    Greece: '\uD83C\uDDEC\uD83C\uDDF7', Croatia: '\uD83C\uDDED\uD83C\uDDF7', Lebanon: '\uD83C\uDDF1\uD83C\uDDE7',
    Uruguay: '\uD83C\uDDFA\uD83C\uDDFE', Bulgaria: '\uD83C\uDDE7\uD83C\uDDEC', Finland: '\uD83C\uDDEB\uD83C\uDDEE',
  };
  return flags[name] || '\uD83C\uDFF3\uFE0F';
}

function ensureBackdrop() {
  var backdrop = document.querySelector('.backdrop');
  if (!backdrop) {
    backdrop = document.createElement('div');
    backdrop.className = 'backdrop';
    document.body.appendChild(backdrop);
  }
  setTimeout(function() { backdrop.classList.add('visible'); }, 10);
  backdrop.addEventListener('click', closePanel, { once: true });
}

function closePanel() {
  var panel = document.getElementById('countryPanel');
  if (panel) panel.setAttribute('aria-hidden', 'true');
  selectedCountry = null;
  clearArcHighlight();
  renderMapColors();
  var backdrop = document.querySelector('.backdrop');
  if (backdrop) backdrop.classList.remove('visible');
}

function initPanelClose() {
  var btn = document.getElementById('panelClose');
  if (btn) btn.addEventListener('click', closePanel);
}

// ---- FLOW TABLE ----
function initFlowTable() {
  var thead = document.getElementById('flowTableHead');
  if (!thead) return;

  thead.querySelectorAll('th[data-sort]').forEach(function(th) {
    th.style.cursor = 'pointer';
    th.addEventListener('click', function() {
      var col = th.dataset.sort;
      if (flowSortCol === col) {
        flowSortDir = flowSortDir === 'asc' ? 'desc' : 'asc';
      } else {
        flowSortCol = col;
        flowSortDir = 'desc';
      }
      refreshFlowTable();
      updateSortIndicators();
    });
  });

  refreshFlowTable();

  var searchInput = document.getElementById('flowSearch');
  if (searchInput) searchInput.addEventListener('input', refreshFlowTable);
}

function updateSortIndicators() {
  var thead = document.getElementById('flowTableHead');
  if (!thead) return;
  thead.querySelectorAll('th[data-sort]').forEach(function(th) {
    th.classList.toggle('sorted-asc', th.dataset.sort === flowSortCol && flowSortDir === 'asc');
    th.classList.toggle('sorted-desc', th.dataset.sort === flowSortCol && flowSortDir === 'desc');
  });
}

function refreshFlowTable() {
  var tbody = document.getElementById('flowTableBody');
  var searchInput = document.getElementById('flowSearch');
  if (!tbody) return;

  var filter = searchInput ? searchInput.value.toLowerCase() : '';

  var flows = FLOW_ANCHORS.map(function(f) {
    return {
      from: f.from,
      to: f.to,
      value: getFlowValue(f.from, f.to, currentYear),
    };
  }).filter(function(f) {
    return f.value !== null && f.value > 0 &&
      (f.from.toLowerCase().includes(filter) || f.to.toLowerCase().includes(filter));
  });

  flows.sort(function(a, b) {
    var va, vb;
    if (flowSortCol === 'value') { va = a.value; vb = b.value; }
    else if (flowSortCol === 'from') { va = a.from; vb = b.from; }
    else if (flowSortCol === 'to') { va = a.to; vb = b.to; }
    if (typeof va === 'string') {
      return flowSortDir === 'asc' ? va.localeCompare(vb) : vb.localeCompare(va);
    }
    return flowSortDir === 'asc' ? va - vb : vb - va;
  });

  tbody.innerHTML = '';
  flows.forEach(function(flow) {
    var row = document.createElement('tr');
    row.dataset.from = flow.from;
    row.dataset.to = flow.to;

    var yoyEl = '';
    var prevYr = currentYear > 2000 ? currentYear - 1 : currentYear;
    var prevVal = getFlowValue(flow.from, flow.to, prevYr);
    if (prevVal && prevVal > 0) {
      var yoy = ((flow.value - prevVal) / prevVal) * 100;
      var yoyClass = yoy >= 0 ? 'up' : 'down';
      var yoyTxt = (yoy >= 0 ? '\u2191' : '\u2193') + Math.abs(yoy).toFixed(1) + '%';
      yoyEl = '<span class="flow-yoy ' + yoyClass + '">' + yoyTxt + '</span>';
    } else {
      yoyEl = '<span class="flow-yoy">\u2014</span>';
    }

    row.innerHTML =
      '<td><span class="flow-from">' + flow.from + '</span>' +
        '<span class="flow-arrow">\u2192</span><span class="flow-to">' + flow.to + '</span></td>' +
      '<td class="td-value">\u20AC' + flow.value.toFixed(2) + 'B</td>' +
      '<td>' + yoyEl + '</td>';

    row.addEventListener('click', function() {
      document.querySelectorAll('.flow-table tbody tr').forEach(function(r) { r.classList.remove('highlighted'); });
      row.classList.add('highlighted');
      var arc = document.querySelector('.trade-arc[data-from="' + flow.from + '"][data-to="' + flow.to + '"]');
      if (arc) highlightArc(arc, flow);
    });

    tbody.appendChild(row);
  });
}

// ---- UPDATE FOR YEAR ----
function updateForYear(yr) {
  // Update sparkline
  updateSparklineForYear(yr);

  // Update key facts
  updateKeyFacts(yr);

  // Update header subtitle
  var subtitleEl = document.querySelector('.app-subtitle');
  var ydEl = document.getElementById('yearDisplay');
  if (ydEl) {
    ydEl.textContent = yr;
  } else if (subtitleEl) {
    subtitleEl.innerHTML = '<span id="yearDisplay">' + yr + '</span> Annual Data \u00B7 Billion EUR';
  }

  // Update map colors and arcs
  renderMapColors();
  renderArcs();

  // Update flow table
  refreshFlowTable();

  // Update legend scale labels
  updateLegendLabels(yr);

  // Update insights carousel text
  updateInsightsText(yr);
}

function updateKeyFacts(yr) {
  var gv = YEARLY_GLOBAL[yr] || YEARLY_GLOBAL[2024];
  var prevYr = yr > 2000 ? yr - 1 : yr;
  var gvPrev = YEARLY_GLOBAL[prevYr] || gv;

  var yoyVol = gvPrev.vol ? ((gv.vol - gvPrev.vol) / gvPrev.vol) * 100 : 0;
  var yoyVal = gvPrev.val ? ((gv.val - gvPrev.val) / gvPrev.val) * 100 : 0;

  var expData = buildYearData(yr).expData;
  var impData = buildYearData(yr).impData;

  // Top exporter
  var topExpName = 'France';
  var topExpVal = 0;
  Object.keys(expData).forEach(function(c) {
    if (expData[c] > topExpVal) {
      topExpVal = expData[c];
      topExpName = c;
    }
  });

  // Top importer
  var topImpName = 'USA';
  var topImpVal = 0;
  Object.keys(impData).forEach(function(c) {
    if (impData[c] > topImpVal) {
      topImpVal = impData[c];
      topImpName = c;
    }
  });

  // Top bilateral
  var flows = FLOW_ANCHORS.map(function(f) {
    return { from: f.from, to: f.to, value: getFlowValue(f.from, f.to, yr) };
  }).filter(function(f) { return f.value !== null && f.value > 0; })
    .sort(function(a, b) { return b.value - a.value; });
  var topFlow = flows[0] || { from: 'France', to: 'USA', value: 2.6 };

  // Update fact cards
  var factValues = document.querySelectorAll('.fact-value');
  var factCards = document.querySelectorAll('.fact-card');

  if (factCards[0]) {
    factCards[0].querySelector('.fact-value').textContent = '\u20AC' + gv.val.toFixed(1) + 'B';
    var volCard = factCards[0].querySelector('.fact-yoy');
    if (volCard) volCard.textContent = (yoyVal >= 0 ? '\u2191' : '\u2193') + Math.abs(yoyVal).toFixed(1) + '% YoY';
  }
  if (factCards[1]) {
    factCards[1].querySelector('.fact-value').textContent = gv.vol.toFixed(1) + 'M hL';
    var volCard2 = factCards[1].querySelector('.fact-yoy');
    if (volCard2) {
      volCard2.textContent = (yoyVol >= 0 ? '\u2191' : '\u2193') + Math.abs(yoyVol).toFixed(1) + '% YoY';
      volCard2.className = 'fact-yoy ' + (yoyVol >= 0 ? 'up' : 'down');
    }
  }
  if (factCards[2]) {
    factCards[2].querySelector('.fact-value').textContent = '\u20AC' + topExpVal.toFixed(1) + 'B';
    factCards[2].querySelector('.fact-sub').textContent = topExpName;
    factCards[2].querySelector('.fact-icon').textContent = getCountryFlag(topExpName);
  }
  if (factCards[3]) {
    factCards[3].querySelector('.fact-value').textContent = '\u20AC' + topImpVal.toFixed(1) + 'B';
    factCards[3].querySelector('.fact-sub').textContent = topImpName;
    factCards[3].querySelector('.fact-icon').textContent = getCountryFlag(topImpName);
  }
  if (factCards[4]) {
    factCards[4].querySelector('.fact-value').textContent = '\u20AC' + topFlow.value.toFixed(2) + 'B';
    factCards[4].querySelector('.fact-sub').textContent = topFlow.from + ' \u2192 ' + topFlow.to;
  }

  // Event annotation in key facts
  if (EVENTS[yr] && factCards[5]) {
    factCards[5].querySelector('.fact-value').textContent = EVENTS[yr];
    factCards[5].querySelector('.fact-value').style.fontSize = '0.72rem';
    factCards[5].querySelector('.fact-icon').textContent = '\uD83D\uDCCA';
  }
}

function updateLegendLabels(yr) {
  var legendMin = document.getElementById('legendMin');
  var legendMax = document.getElementById('legendMax');
  if (!legendMin || !legendMax) return;

  if (currentView === 'export') {
    legendMin.textContent = '0.2B';
    legendMax.textContent = '\u20AC12B';
  } else if (currentView === 'import') {
    legendMin.textContent = '0.2B';
    legendMax.textContent = '\u20AC6B';
  } else {
    legendMin.textContent = 'Deficit';
    legendMax.textContent = 'Surplus';
  }
}

function updateInsightsText(yr) {
  var cards = document.querySelectorAll('.insight-card');
  if (!cards || cards.length === 0) return;

  var templates = [
    '<span class="insight-icon">\uD83C\uDF77</span><span class="insight-headline">France dominates global exports</span><span class="insight-detail">More than the next 3 countries combined \u2014 \u20AC{{val}}bn in {{year}}</span>',
    '<span class="insight-icon">\uD83C\uDDE6\uD83C\uDDFA</span><span class="insight-headline">Australia wine exports</span><span class="insight-detail">\u20AC{{au_val}}bn in {{year}} \u2014 China recovery underway</span>',
    '<span class="insight-icon">\uD83C\uDDFA\uD83C\uDDF8</span><span class="insight-headline">USA \u2014 world\'s biggest importer</span><span class="insight-detail">\u20AC{{us_val}}bn in {{year}} \u2014 18% of global imports</span>',
    '<span class="insight-icon">\uD83C\uDDE8\uD83C\uDDF3</span><span class="insight-headline">China wine market</span><span class="insight-detail">{{cn_val}}bn EUR in {{year}} \u2014 {{cn_yoy}} from prior year</span>',
    '<span class="insight-icon">\uD83C\uDFFB</span><span class="insight-headline">Global wine trade value</span><span class="insight-detail">\u20AC{{val}}B in {{year}} \u2014 {{yoy}} from previous year</span>',
    '<span class="insight-icon">\uD83C\uDFE6</span><span class="insight-headline">Global wine trade volume</span><span class="insight-detail">{{vol}}M hL in {{year}} \u2014 {{yoy_vol}} vs prior year</span>',
    '<span class="insight-icon">\uD83C\uDDEE\uD83C\uDDF9</span><span class="insight-headline">Italy \u2014 #2 exporter</span><span class="insight-detail">\u20AC{{it_val}}bn in {{year}} \u2014 strong bulk wine performance</span>',
    '<span class="insight-icon">\uD83C\uDDEA\uD83C\uDDF8</span><span class="insight-headline">Spain \u2014 high volume, value lags</span><span class="insight-detail">Bulk wine powerhouse \u2014 volume leader, price discounter</span>',
  ];

  var gv = YEARLY_GLOBAL[yr] || YEARLY_GLOBAL[2024];
  var prevYr = yr > 2000 ? yr - 1 : yr;
  var gvPrev = YEARLY_GLOBAL[prevYr] || gv;
  var yoyVal = gvPrev.val ? (((gv.val - gvPrev.val) / gvPrev.val) * 100).toFixed(1) : '0.0';
  var yoyVol = gvPrev.vol ? (((gv.vol - gvPrev.vol) / gvPrev.vol) * 100).toFixed(1) : '0.0';
  var expFr = getExporterValue('France', yr);
  var expAu = getExporterValue('Australia', yr);
  var impUs = getImporterValue('USA', yr);
  var impCn = getImporterValue('mainland China', yr);
  var impCnPrev = getImporterValue('mainland China', prevYr);
  var cnYoy = impCnPrev ? (((impCn - impCnPrev) / impCnPrev) * 100).toFixed(1) : '0.0';
  var expIt = getExporterValue('Italy', yr);

  var replacements = {
    '{{year}}': yr,
    '{{val}}': (expFr || 0).toFixed(1),
    '{{au_val}}': (expAu || 0).toFixed(1),
    '{{us_val}}': (impUs || 0).toFixed(1),
    '{{cn_val}}': (impCn || 0).toFixed(2),
    '{{cn_yoy}}': (parseFloat(cnYoy) >= 0 ? '+' : '') + cnYoy + '%',
    '{{vol}}': gv.vol,
    '{{yoy}}': (parseFloat(yoyVal) >= 0 ? '+' : '') + yoyVal + '%',
    '{{yoy_vol}}': (parseFloat(yoyVol) >= 0 ? '+' : '') + yoyVol + '%',
    '{{it_val}}': (expIt || 0).toFixed(1),
  };

  templates.forEach(function(tmpl, i) {
    if (cards[i]) {
      var html = tmpl;
      Object.keys(replacements).forEach(function(k) {
        html = html.split(k).join(replacements[k]);
      });
      cards[i].innerHTML = html;
    }
  });
}

function fmtYoy(v) {
  if (v === null || v === undefined) return '\u2014';
  return (v >= 0 ? '\u2191' : '\u2193') + Math.abs(v).toFixed(1) + '%';
}

// Initialize
document.addEventListener('DOMContentLoaded', init);
